def get_db_connection():
    """Create a database connection using environment variables."""
    connection = pymysql.connect(
        host=os.environ.get('DB_HOST', '127.0.0.1'),
        user=os.environ.get('DB_USER'),
        password=os.environ.get('DB_PASSWORD'),
        database=os.environ.get('DB_NAME'),
        port=int(os.environ.get('DB_PORT', 3306)),
        unix_socket=os.environ.get('DB_SOCKET', None),
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=10,
        read_timeout=10,
        write_timeout=10,
    )
    return connection


# Allowlists to prevent injection via column/table names
ALLOWED_TABLES = {'products', 'users', 'orders', 'categories', 'inventory'}

ALLOWED_COLUMNS = {
    'products': {'id', 'name', 'description', 'price', 'category_id', 'created_at', 'status', 'sku'},
    'users': {'id', 'username', 'email', 'created_at', 'status', 'role'},
    'orders': {'id', 'user_id', 'status', 'total', 'created_at', 'updated_at'},
    'categories': {'id', 'name', 'description', 'parent_id'},
    'inventory': {'id', 'product_id', 'quantity', 'warehouse_id', 'updated_at'},
}

ALLOWED_OPERATORS = {'=', '!=', '>', '<', '>=', '<=', 'LIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL', 'BETWEEN'}

ALLOWED_SORT_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 1000
DEFAULT_LIMIT = 50
MAX_FILTERS = 20


def validate_table(table_name):
    """Validate table name against allowlist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table: '{table_name}'. Allowed tables: {', '.join(sorted(ALLOWED_TABLES))}")
    return table_name


def validate_column(table_name, column_name):
    """Validate column name against allowlist for the given table."""
    allowed = ALLOWED_COLUMNS.get(table_name, set())
    if column_name not in allowed:
        raise ValueError(
            f"Invalid column: '{column_name}' for table '{table_name}'. "
            f"Allowed columns: {', '.join(sorted(allowed))}"
        )
    return column_name


def validate_operator(operator):
    """Validate SQL operator against allowlist."""
    op_upper = operator.upper().strip()
    if op_upper not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator: '{operator}'. Allowed operators: {', '.join(sorted(ALLOWED_OPERATORS))}")
    return op_upper


def validate_limit(limit):
    """Validate and sanitize limit value."""
    try:
        limit = int(limit)
    except (TypeError, ValueError):
        return DEFAULT_LIMIT
    if limit < 1:
        return 1
    if limit > MAX_LIMIT:
        return MAX_LIMIT
    return limit


def validate_offset(offset):
    """Validate and sanitize offset value."""
    try:
        offset = int(offset)
    except (TypeError, ValueError):
        return 0
    if offset < 0:
        return 0
    return offset


def build_search_query(table, filters=None, sort_by=None, sort_dir=None,
                       limit=DEFAULT_LIMIT, offset=0, select_columns=None):
    """
    Build a parameterized search query safely.

    Uses allowlists for table/column/operator names and parameterized queries
    for all user-supplied values. NEVER concatenates user input into SQL.

    Args:
        table: Table name (must be in ALLOWED_TABLES)
        filters: List of dicts with 'column', 'operator', 'value' keys
        sort_by: Column name to sort by
        sort_dir: Sort direction (ASC or DESC)
        limit: Max rows to return
        offset: Row offset for pagination
        select_columns: List of column names to select (None = all allowed columns)

    Returns:
        Tuple of (query_string, params_tuple)
    """
    # Validate table
    validated_table = validate_table(table)

    # Build SELECT clause using only validated column names
    if select_columns:
        validated_select = []
        for col in select_columns:
            validated_select.append(f"`{validate_column(validated_table, col)}`")
        select_clause = ', '.join(validated_select)
    else:
        select_clause = ', '.join(
            f"`{col}`" for col in sorted(ALLOWED_COLUMNS[validated_table])
        )

    # Start building query - table name is from allowlist, safe to format
    query = f"SELECT {select_clause} FROM `{validated_table}`"
    params = []

    # Build WHERE clause with parameterized values
    if filters:
        if len(filters) > MAX_FILTERS:
            raise ValueError(f"Too many filters. Maximum allowed: {MAX_FILTERS}")

        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f.get('column', ''))
            operator = validate_operator(f.get('operator', '='))
            value = f.get('value')

            if operator in ('IS NULL', 'IS NOT NULL'):
                # No value needed for NULL checks
                where_clauses.append(f"`{column}` {operator}")

            elif operator == 'IN' or operator == 'NOT IN':
                # Value should be a list
                if not isinstance(value, list) or len(value) == 0:
                    raise ValueError(f"Operator '{operator}' requires a non-empty list value")
                if len(value) > 100:
                    raise ValueError(f"IN clause limited to 100 values")
                placeholders = ', '.join(['%s'] * len(value))
                where_clauses.append(f"`{column}` {operator} ({placeholders})")
                params.extend(value)

            elif operator == 'BETWEEN':
                # Value should be a list of exactly 2 elements
                if not isinstance(value, list) or len(value) != 2:
                    raise ValueError("BETWEEN operator requires a list of exactly 2 values")
                where_clauses.append(f"`{column}` BETWEEN %s AND %s")
                params.extend(value)

            elif operator == 'LIKE':
                # Escape LIKE wildcards in user input, then wrap with %
                if not isinstance(value, str):
                    raise ValueError("LIKE operator requires a string value")
                # Escape special LIKE characters in the user's input
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(f"%{escaped_value}%")

            else:
                # Standard comparison operators: =, !=, >, <, >=, <=
                where_clauses.append(f"`{column}` {operator} %s")
                params.append(value)

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    # Build ORDER BY clause using validated column name
    if sort_by:
        validated_sort_col = validate_column(validated_table, sort_by)
        validated_sort_dir = 'ASC'
        if sort_dir and sort_dir.upper().strip() in ALLOWED_SORT_DIRECTIONS:
            validated_sort_dir = sort_dir.upper().strip()
        query += f" ORDER BY `{validated_sort_col}` {validated_sort_dir}"

    # Add LIMIT and OFFSET with parameterized values
    validated_limit = validate_limit(limit)
    validated_offset = validate_offset(offset)
    query += " LIMIT %s OFFSET %s"
    params.extend([validated_limit, validated_offset])

    return query, tuple(params)


