def parse_request_filters(request_json):
    """
    Parse and validate filters from the HTTP request body.

    Expected request format:
    {
        "table": "products",
        "filters": [
            {"column": "name", "operator": "LIKE", "value": "widget"},
            {"column": "price", "operator": ">=", "value": 10.00},
            {"column": "status", "operator": "=", "value": "active"},
            {"column": "category_id", "operator": "IN", "value": [1, 2, 3]}
        ],
        "select": ["id", "name", "price", "status"],
        "sort_by": "price",
        "sort_dir": "DESC",
        "limit": 25,
        "offset": 0,
        "include_count": true
    }
    """
    if not request_json:
        raise ValueError("Request body is required and must be valid JSON")

    if not isinstance(request_json, dict):
        raise ValueError("Request body must be a JSON object")

    table = request_json.get('table')
    if not table or not isinstance(table, str):
        raise ValueError("'table' is required and must be a string")

    filters = request_json.get('filters', [])
    if not isinstance(filters, list):
        raise ValueError("'filters' must be a list")

    # Validate each filter has required structure
    validated_filters = []
    for i, f in enumerate(filters):
        if not isinstance(f, dict):
            raise ValueError(f"Filter at index {i} must be a JSON object")
        if 'column' not in f:
            raise ValueError(f"Filter at index {i} missing 'column'")
        if 'operator' not in f:
            raise ValueError(f"Filter at index {i} missing 'operator'")

        operator = f['operator'].upper().strip()
        if operator not in ('IS NULL', 'IS NOT NULL') and 'value' not in f:
            raise ValueError(f"Filter at index {i} missing 'value' (required for operator '{operator}')")

        validated_filters.append({
            'column': str(f['column']).strip(),
            'operator': str(f['operator']).strip(),
            'value': f.get('value'),
        })

    select_columns = request_json.get('select')
    if select_columns is not None:
        if not isinstance(select_columns, list):
            raise ValueError("'select' must be a list of column names")
        select_columns = [str(c).strip() for c in select_columns]

    sort_by = request_json.get('sort_by')
    if sort_by is not None:
        sort_by = str(sort_by).strip()

    sort_dir = request_json.get('sort_dir')
    if sort_dir is not None:
        sort_dir = str(sort_dir).strip()

    limit = request_json.get('limit', DEFAULT_LIMIT)
    offset = request_json.get('offset', 0)
    include_count = bool(request_json.get('include_count', False))

    return {
        'table': table.strip(),
        'filters': validated_filters,
        'select_columns': select_columns,
        'sort_by': sort_by,
        'sort_dir': sort_dir,
        'limit': limit,
        'offset': offset,
        'include_count': include_count,
    }


def search_api(request):
    """
    Cloud Function entry point for the search API.

    Handles HTTP POST requests with JSON body containing search parameters.
    All queries use parameterized statements to prevent SQL injection.
    Table and column names are validated against strict allowlists.
    """
    # CORS headers
    headers = {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': os.environ.get('ALLOWED_ORIGIN', '*'),
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    }

    # Handle CORS preflight
    if request.method == 'OPTIONS':
        return ('', 204, headers)

    # Only allow POST
    if request.method != 'POST':
        return (
            json.dumps({'error': 'Method not allowed. Use POST.'}),
            405,
            headers,
        )

    # Check content type
    content_type = request.content_type or ''
    if 'application/json' not in content_type:
        return (
            json.dumps({'error': 'Content-Type must be application/json'}),
            400,
            headers,
        )

    connection = None
    try:
        # Parse request
        request_json = request.get_json(silent=True)
        parsed = parse_request_filters(request_json)

        # Build parameterized query - NO string concatenation of user values
        query, params = build_search_query(
            table=parsed['table'],
            filters=parsed['filters'],
            sort_by=parsed['sort_by'],
            sort_dir=parsed['sort_dir'],
            limit=parsed['limit'],
            offset=parsed['offset'],
            select_columns=parsed['select_columns'],
        )

        # Execute query with parameterized values
        connection = get_db_connection()
        with connection.cursor() as cursor:
            cursor.execute(query, params)
            results = cursor.fetchall()

        # Convert any non-serializable types (dates, decimals, etc.)
        serializable_results = _make_serializable(results)

        response_data = {
            'success': True,
            'data': serializable_results,
            'pagination': {
                'limit': validate_limit(parsed['limit']),
                'offset': validate_offset(parsed['offset']),
                'returned': len(serializable_results),
            },
        }

        # Optionally include total count for pagination
        if parsed['include_count']:
            count_query, count_params = build_count_query(
                table=parsed['table'],
                filters=parsed['filters'],
            )
            with connection.cursor() as cursor:
                cursor.execute(count_query, count_params)
                count_result = cursor.fetchone()
                response_data['pagination']['total'] = count_result['total']

        return (json.dumps(response_data, default=str), 200, headers)

    except ValueError as e:
        return (
            json.dumps({'success': False, 'error': f'Validation error: {str(e)}'}),
            400,
            headers,
        )
    except pymysql.err.OperationalError as e:
        # Don't leak database details to the client
        error_code = e.args[0] if e.args else 'unknown'
        print(f"Database operational error: {e}")
        return (
            json.dumps({'success': False, 'error': f'Database connection error (code: {error_code})'}),
            503,
            headers,
        )
    except pymysql.err.ProgrammingError as e:
        print(f"Database programming error: {e}")
        return (
            json.dumps({'success': False, 'error': 'Invalid query parameters'}),
            400,
            headers,
        )
    except Exception as e:
        # Log the full error server-side, return generic message to client
        print(f"Unexpected error: {type(e).__name__}: {e}")
        return (
            json.dumps({'success': False, 'error': 'Internal server error'}),
            500,
            headers,
        )
    finally:
        if connection:
            try:
                connection.close()
            except Exception:
                pass


def _make_serializable(results):
    """Convert query results to JSON-serializable format."""
    import decimal
    import datetime

    serializable = []
    for row in results:
        clean_row = {}
        for key, value in row.items():
            if isinstance(value, decimal.Decimal):
                clean_row[key] = float(value)
            elif isinstance(value, (datetime.datetime, datetime.date)):
                clean_row[key] = value.isoformat()
            elif isinstance(value, bytes):
                clean_row[key] = value.decode('utf-8', errors='replace')
            else:
                clean_row[key] = value
        serializable.append(clean_row)
    return serializable


